#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int s[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &s[i]);
        }
        int dp[n][2]; // dp[i][0] for even index, dp[i][1] for odd index
        dp[0][0] = 1;
        dp[0][1] = 0;
        for (int i = 1; i < n; i++) {
            if (i % 2 == 0) {
                if (s[i] >= s[i-1]) {
                    dp[i][0] = dp[i-1][1] + 1;
                } else {
                    dp[i][0] = 1;
                }
                dp[i][1] = 0;
            } else {
                if (s[i] <= s[i-1]) {
                    dp[i][1] = dp[i-1][0] + 1;
                } else {
                    dp[i][1] = 1;
                }
                dp[i][0] = 0;
            }
        }
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            maxLen = (maxLen > dp[i][0]) ? maxLen : dp[i][0];
            maxLen = (maxLen > dp[i][1]) ? maxLen : dp[i][1];
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

