            int n = sc.nextInt();
            int[] s = new int[n];
            for (int i = 0; i < n; i++) {
                s[i] = sc.nextInt();
            }
            int[][] dp = new int[n][2]; // dp[i][0] for even index, dp[i][1] for odd index
            dp[0][0] = 1;
            dp[0][1] = 0;
            for (int i = 1; i < n; i++) {
                if (i % 2 == 0) {
                    if (s[i] >= s[i-1]) {
                        dp[i][0] = dp[i-1][1] + 1;
                    } else {
                        dp[i][0] = 1;
                    }
                    dp[i][1] = 0;
                } else {
                    if (s[i] <= s[i-1]) {
                        dp[i][1] = dp[i-1][0] + 1;
                    } else {
                        dp[i][1] = 1;
                    }
                    dp[i][0] = 0;
                }
            }
            int maxLen = 0;
            for (int i = 0; i < n; i++) {
                maxLen = Math.max(maxLen, dp[i][0]);
